these examples to index fields as the dateFacet type.To learn how to set up and run the following example code, see
Define the Index for the token Type.Representation ExampleThe following index definition for the
`sample_analytics.accounts` collection in the [sample data sets](available-sample-datasets) indexes the
`account_id` field with 64-bit integer values. The
following example also:* Indexes all other integer values in the `account_id` field.

* Rounds any decimal values and indexes small double type
  values in the `account_id` field.```cpp
#include <iostream>

#include <bsoncxx/builder/basic/document.hpp>
#include <bsoncxx/json.hpp>
#include <mongocxx/client.hpp>
#include <mongocxx/instance.hpp>
#include <mongocxx/uri.hpp>

using bsoncxx::builder::basic::kvp;
using bsoncxx::builder::basic::make_document;

int main(){

    mongocxx::instance instance;
    mongocxx::uri uri("<connection-string>");
    mongocxx::client client(uri);

    auto db = client["sample_analytics"];
    auto collection = db["accounts"];

    // instantiate a ``mongocxx::search_index_view`` on your collection
    auto siv = collection.search_indexes();

    {
        auto name = "default";
        auto definition = make_document(
            kvp("mappings", make_document(
                kvp("dynamic", false),
                kvp("fields", make_document(
                    kvp("account_id", make_document(
                        kvp("type", "number"),
                        kvp("representation", "int64")
                    ))
                ))
            ))
        );

        auto model = mongocxx::search_index_model(name, definition.view());

        // Create the search index
        auto result = siv.create_one(model);
        std::cout << "New index name: " << result << std::endl;
    }
}
